mapper.select:


    c.is_deleted = #{isDeleted}
    and c.ctype = #{ctype}
    and c.cars_num like concat('%', #{carsNum}, '%')
    and c.cars_xh like concat('%', #{carsXh}, '%')
    and c.cars_comp = #{carsComp}
    and c.mine = #{mine}
    and c.teamid = #{teamid}
    and c.rfid like concat('%', #{rfid}, '%')
    and c.status = #{status}

order by c.id desc
